import{_ as e,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Data Integration Implementation Guide","description":"","frontmatter":{"title":"Data Integration Implementation Guide","slug":"data-integration-implementation-guide"},"headers":[],"relativePath":"marketer-hub/data-integration-implementation-guide.md","filePath":"marketer-hub/data-integration-implementation-guide.md"}'),i={name:"marketer-hub/data-integration-implementation-guide.md"};function d(s,t,o,l,c,p){return a(),r("div",null,[...t[0]||(t[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Data Integrations provide an easy way to automatically send Branch data to your other analytics services and marketing tools using pre-formatted webhooks.</p><p>This guide will walk you through how to send your Branch data to our Data Integration partners. For most integrations, configuration just requires you to input your credentials and hit &quot;Enable&quot;.</p><h3 id="data-limitations" tabindex="-1">Data limitations <a class="header-anchor" href="#data-limitations" aria-label="Permalink to &quot;Data limitations&quot;">​</a></h3><p>Please note that installs and other events attributed to Facebook Ads, Snap, Twitter Ads, or TikTok will not be sent to third parties via Data Integrations.</p><p>For more information, please refer to the following:</p><ul><li><a href="./facebook-ads-overview.html#data-limitations">Facebook Ads Data Limitations</a></li><li><a href="./snap.html#exporting-snap-data">Exporting Snap Data</a></li><li><a href="./twitter-ads.html#twitter-data-sharing">Twitter Ads Data Sharing</a></li><li><a href="./tiktok-for-business.html#data-sharing">TikTok Data Sharing</a></li></ul><h3 id="ios-14-5-data-changes" tabindex="-1">iOS 14.5 data changes <a class="header-anchor" href="#ios-14-5-data-changes" aria-label="Permalink to &quot;iOS 14.5 data changes&quot;">​</a></h3><p>Apple requires users to opt into sharing their device data through Apple&#39;s <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer">AppTrackingTransparency</a> framework. When an install is attributed to paid ads, a 2nd install event will fire post user opt-in</p><p>Opt-ins will affect your paid ads attributed install events as they will be delayed until opt-in. No data will be available for opted-out users unless another Branch-attributed channel was encountered (Short Link, Journeys, Email, etc.). Our recommendation is to use a different identifier (ex. IDFV) to de-dupe install events on your partner systems.</p><p>For additional information on changes post iOS 14.5, visit our <a href="./ios-14-faqs-1.html">FAQ pages</a></p><h2 id="_1-verify-the-data-partner-accepts-the-events-you-want" tabindex="-1">1. Verify the data partner accepts the events you want <a class="header-anchor" href="#_1-verify-the-data-partner-accepts-the-events-you-want" aria-label="Permalink to &quot;1. Verify the data partner accepts the events you want&quot;">​</a></h2><p>The events Branch sends to third party data tools varies based on the events the partner supports as well as whether or not you&#39;ve implemented the Branch SDK to measure said events.</p><p>All non-attributed events will be excluded. Branch also sends all the data that is attached to the link that drove the referred event. This will allow you to analyze which campaigns, channels, etc. are helping you acquire and engage users.</p><details><summary>VIEW BRANCH EVENTS SENT TO PARTNER</summary><table tabindex="0"><thead><tr><th>Data Integration Partner</th><th>Branch Events Sent to Partner</th></tr></thead><tbody><tr><td>24Metrics Fraudshield</td><td>- Install Events - Click Events - Commerce Events</td></tr><tr><td>Adform</td><td>- Install Events - Commerce Events - Custom Events - Open Events</td></tr><tr><td>Adjust</td><td>- Click Events</td></tr><tr><td>Admost</td><td>- Install Events</td></tr><tr><td>Adobe Analytics (Data Connector)</td><td>- <a href="https://help.branch.io/partners-portal/docs/adobe-analytics?highlight=adobe%20analytics" target="_blank" rel="noreferrer">View Adobe Analytics (Data Connector) Specific Guide Here</a></td></tr><tr><td>Adobe Analytics (Processing Rules)</td><td>- <a href="./adobe-analytics.html">View Adobe Analytics (Processing Rules) Specific Guide Here</a></td></tr><tr><td>Adoya</td><td>- Install Events - Commerce Events</td></tr><tr><td>Airship</td><td>- <a href="./airship.html">View Airship Specific Guide Here</a></td></tr><tr><td>Amplitude</td><td>- Install Events - Open Events - Reinstall Events - Commerce Events - Custom Events</td></tr><tr><td>AppMetrica</td><td>- Click Events</td></tr><tr><td>AppsFlyer</td><td>- Click Events ⚠ AppsFlyer does NOT accept query params on the end of Branch Links ⚠ AppsFlyer may not properly attribute installs to Journeys and other Branch Link clicks due to lack of IDFA on click ⚠ There may be a delay in clicks arriving at AppsFlyer via Webhook and the install event being sent to AppsFlyer by the AppsFlyer SDK</td></tr><tr><td>Appsee</td><td>- Install Events</td></tr><tr><td>Apptilaus - Subscription Analytics</td><td>- Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Apxor</td><td>- Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Backinapp</td><td>- Install Events - Reinstall Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Batch</td><td>- <a href="./batch.html">View Batch Specific Guide Here</a></td></tr><tr><td>Bluecore</td><td>- Commerce Events</td></tr><tr><td>Braze</td><td>- <a href="./braze.html">View Braze Specific Guide Here</a></td></tr><tr><td>Bubbleye</td><td>- Click Events - Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Chartable</td><td>- Install Events - Commerce Events - Custom Events</td></tr><tr><td>Claritas</td><td>- Install Events - Open Events - Custom Events</td></tr><tr><td>CleverTap</td><td>- <a href="./clevertap.html">View CleverTap Specific Guide Here</a></td></tr><tr><td>Convertro</td><td>- Click Events - Install Events - Reinstall Events - Open Events - Custom Events</td></tr><tr><td>Dataplusmath</td><td>- Install Events - Open Events - Commerce Events - User Lifecycle Events - Custom Events</td></tr><tr><td>Eulerian</td><td>- Click Events - Impression Events - Install Events - Open Events - Commerce Events</td></tr><tr><td>FollowAnalytics</td><td>- Install Events</td></tr><tr><td>Forensiq</td><td>- Click Events - Install Events</td></tr><tr><td>Fraudscore</td><td>- Install Events - Commerce Events - Custom Events</td></tr><tr><td>Fraud Defense</td><td>- Install Events</td></tr><tr><td>Google Analytics</td><td>- <a href="./google-analytics.html">View Google Analytics Specific Guide Here</a></td></tr><tr><td>Google Analytics 4</td><td>- <a href="./google-analytics-4-configuration.html">View Google Analytics 4 Specific Guide Here</a></td></tr><tr><td>Google Firebase</td><td>- <a href="./firebase.html">View Google Firebase Specific Guide Here</a></td></tr><tr><td>iCubes Pro</td><td>- Install Events - Commerce Events</td></tr><tr><td>Insider</td><td>- Install Events - Commerce Events - Custom Events</td></tr><tr><td>Iterable</td><td>- Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Kochava</td><td>- Click Events</td></tr><tr><td>Leanplum</td><td>- <a href="./leanplum.html">View Leanplum Specific Guide Here</a></td></tr><tr><td>Localytics</td><td>- Install Events</td></tr><tr><td>Machine Advertising</td><td>- Install Events - Commerce Events - Custom Events</td></tr><tr><td>mFilterit</td><td>- Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Mixpanel</td><td>- <a href="./mixpanel.html">View Mixpanel Specific Guide Here</a></td></tr><tr><td>MobileAction</td><td>- Install Events - Commerce Events</td></tr><tr><td>MovableInk</td><td>- <a href="./movable-ink.html">View MovableInk Specific Guide Here</a></td></tr><tr><td>MoEngage</td><td>- <a href="./moengage.html">View MoEngage Specific Guide Here</a></td></tr><tr><td>mParticle (Import)</td><td>- <a href="./mparticle-import.html">View mParticle Import Specific Guide Here</a></td></tr><tr><td>mParticle (Export)</td><td>- <a href="./mparticle-export.html">View mParticle Export Specific Guide Here</a></td></tr><tr><td>myTracker</td><td>- Click Events</td></tr><tr><td>Netcore Smartech</td><td>- Install Events - Commerce Events - Custom Events</td></tr><tr><td>Neustar</td><td>- Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>NotifyVisitors</td><td>- Install Events - Commerce Events - Custom Events</td></tr><tr><td>Scalarr</td><td>- Install Events - Open Events - Commerce Events - User Lifecycle Events - Custom Events</td></tr><tr><td>SearchAdsHQ</td><td>- Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Segment (Import)</td><td>- <a href="./segment-import.html">View Segment Import Specific Guide Here</a></td></tr><tr><td>Segment (Export)</td><td>- <a href="./segment-export.html">View Segment Export Specific Guide Here</a></td></tr><tr><td>Singular</td><td>- Click Events</td></tr><tr><td>Tealium (Import)</td><td>- <a href="https://help.branch.io/partners-portal/docs/tealium-import" target="_blank" rel="noreferrer">View Tealium Import Specific Guide Here</a></td></tr><tr><td>TrafficGuard</td><td>- Click Events - Install Events - Open Events - Commerce Events - Custom Events</td></tr><tr><td>Visual IQ</td><td>- Install Events - Open Events - Commerce Events - Content - User Lifecycle Events</td></tr><tr><td>WebEngage</td><td>- Install Events</td></tr></tbody></table></details><h2 id="_2-complete-data-integration-prerequisites" tabindex="-1">2. Complete data integration prerequisites <a class="header-anchor" href="#_2-complete-data-integration-prerequisites" aria-label="Permalink to &quot;2. Complete data integration prerequisites&quot;">​</a></h2><p>Before enabling a Data Integration, you&#39;ll need to ensure the Branch SDK is implemented in your app and that you&#39;re tracking the events you want to send to your partner. You&#39;ll also need to have the partner&#39;s SDK installed in your app if required by that partner.</p><p>See our <a href="https://help.branch.io/developer-hub/docs/data-integration-guide-for-developers" target="_blank" rel="noreferrer">developer documentation</a> for implementation details.</p><h2 id="_3-retrieve-keys-credentials-from-your-partner" tabindex="-1">3. Retrieve keys/credentials from your partner <a class="header-anchor" href="#_3-retrieve-keys-credentials-from-your-partner" aria-label="Permalink to &quot;3. Retrieve keys/credentials from your partner&quot;">​</a></h2><p>Find your Partner&#39;s Keys/Credentials. Later, you&#39;ll enter them into the Branch Dashboard.</p><details><summary>FIND PARTNER KEY &amp; METHOD TO PASS TO BRANCH</summary><table tabindex="0"><thead><tr><th>Data Integration Partner</th><th>Partner Key &amp; Method to pass to Branch SDK</th></tr></thead><tbody><tr><td>Adobe Analytics</td><td>- <a href="./adobe-analytics-configuration.html">View Adobe Analytics Specific Guide Here</a></td></tr><tr><td>Airship</td><td>- <a href="./airship.html">View Airship Specific Guide Here</a></td></tr><tr><td>Amplitude</td><td>- Set value for $amplitude_device_id &amp; $amplitude_user_id keys using setRequestMetadataKey() method</td></tr><tr><td>Batch</td><td>- <a href="./batch.html">View Batch Specific Guide Here</a></td></tr><tr><td>Braze</td><td>- <a href="./braze.html">View Braze Specific Guide Here</a></td></tr><tr><td>CleverTap</td><td>- <a href="./clevertap.html">View CleverTap Specific Guide Here</a></td></tr><tr><td>Google Analytics</td><td>- <a href="./google-analytics.html">View Google Analytics Specific Guide Here</a></td></tr><tr><td>Google Analytics 4</td><td>- <a href="./google-analytics-4-configuration.html">View Google Analytics 4 Specific Guide Here</a></td></tr><tr><td>Google Firebase</td><td>- <a href="./firebase.html">View Google Firebase Specific Guide Here</a></td></tr><tr><td>Iterable</td><td>- Set Iterable user ID using setIdentity() method</td></tr><tr><td>Mixpanel</td><td>- <a href="./mixpanel.html">View Mixpanel Specific Guide Here</a></td></tr><tr><td>MoEngage</td><td>- <a href="./moengage.html">View MoEngage Specific Guide Here</a></td></tr><tr><td>Movable Ink</td><td>- <a href="./movable-ink.html">View Movable Ink Specific Guide Here</a></td></tr><tr><td>mParticle</td><td>- <a href="./mparticle-import.html">View mParticle Import Specific Guide Here</a></td></tr><tr><td>mParticle</td><td>- <a href="./mparticle.html">View mParticle Export Specific Guide Here</a></td></tr><tr><td>Segment</td><td>- <a href="./segment-import.html">View Segment Import Specific Guide Here</a></td></tr><tr><td>Segment</td><td>- <a href="./segment-export.html">View Segment Export Specific Guide Here</a></td></tr></tbody></table></details><h2 id="_4-enable-the-integration" tabindex="-1">4. Enable the integration <a class="header-anchor" href="#_4-enable-the-integration" aria-label="Permalink to &quot;4. Enable the integration&quot;">​</a></h2><p>To enable the integration:</p><ol><li>In the left-hand navigation, under the <strong>Exports</strong> section, click <strong>Data Feeds</strong>.</li><li>On the <strong>Data Feeds Manager</strong> page, click the <strong>Data Integrations</strong> tab at the top.</li><li>Search for and click on your data partner.</li><li>Provide the necessary credentials on the data partner&#39;s <strong>Export</strong> page.</li><li>Click <strong>Enable</strong>.</li></ol><h2 id="_5-additional-partner-specific-configuration" tabindex="-1">5. Additional partner-specific configuration <a class="header-anchor" href="#_5-additional-partner-specific-configuration" aria-label="Permalink to &quot;5. Additional partner-specific configuration&quot;">​</a></h2><p>Some partners require additional SDK configuration to pass specific identifiers or metadata to Branch. If your partner requires this step, your development team will need to make SDK updates.</p><p>See our <a href="https://help.branch.io/developer-hub/docs/data-integration-guide-for-developers" target="_blank" rel="noreferrer">developer documentation</a> for implementation details.</p>',27)])])}const u=e(i,[["render",d]]);export{m as __pageData,u as default};
